#include<bits/stdc++.h>
using namespace std;
int n,ans;
int main() {
	string s;
	cin>>n;
	cin>>s;
	for(int i=0; i<n-1; i++) {
		if (s[i]=='V'&&s[i+1]=='K') {
			ans++;
			s[i]='v';
			s[i+1]='k';
		}
	}
	for(int i=0; i<n-1; i++)
		if (s[i+1]==s[i]) {
			ans++;
			cout<<ans;
			return 0;
		}
	cout<<ans;
	return 0;
}
